INSERT INTO countries (slug, name, chinese_name, flag, city, buy, chinese_buy, tip, chinese_tip, shopping_location, reference_url) VALUES
('brunei','Brunei','文莱','🇧🇳','Bandar Seri Begawan','Rattan, woven textiles & local snacks','藤编、织物与当地小吃','Choose compact market crafts and sealed food gifts.','选择轻便的市集手工艺品和密封食品礼物。','Pasarneka Tutong or Tamu Bangar','https://www.trip.com/guide/'),
('cambodia','Cambodia','柬埔寨','🇰🇭','Siem Reap','Silk, pepper & artisan crafts','真丝、贡布胡椒与手工艺','Choose pieces sold by craft workshops and ask about the maker.','优先选择手工艺工坊售卖的作品，并询问制作者。','Craft workshops and central markets','https://www.kkday.com/en/blog/'),
('indonesia','Indonesia','印度尼西亚','🇮🇩','Yogyakarta','Batik, coffee & silverwork','蜡染、咖啡与银饰','Look for hand-stamped or hand-drawn batik, not mass-printed copies.','留意手绘或手工盖印蜡染，避开大批量印花仿品。','Yogyakarta craft shops and markets','https://esim.holafly.com/travel-tips/bali-souvenirs/'),
('laos','Laos','老挝','🇱🇦','Luang Prabang','Textiles, coffee & saa paper','纺织品、咖啡与桑皮纸','Local weaving, basketry and paper crafts make light luggage-friendly gifts.','织物、竹编和桑皮纸工艺品轻便，也很适合送礼。','Luang Prabang night market','https://www.kkday.com/en/blog/'),
('malaysia','Malaysia','马来西亚','🇲🇾','Kuala Terengganu','Batik, songket & snacks','蜡染、宋吉锦与传统零食','Pasar Payang is a good starting point for textiles and traditional snacks.','Pasar Payang 是寻找纺织品和传统小吃的好起点。','Central Market and major supermarkets','https://www.trip.com/guide/'),
('myanmar','Myanmar','缅甸','🇲🇲','Yangon','Lacquerware, longyi & tea','漆器、笼基长裙与茶叶','Prioritise small, durable handmade pieces; check current travel guidance before planning.','优先考虑小巧耐用的手作，并在出行前查看最新旅行建议。','Independent craft shops; verify travel conditions','https://www.kkday.com/en/blog/'),
('philippines','Philippines','菲律宾','🇵🇭','Manila','Woven goods, mangoes & shell crafts','编织品、芒果与贝壳工艺','Protect fragile shell crafts in hand luggage, and ask how the material was sourced.','易碎贝壳工艺品建议随身携带，并询问材料来源。','Department stores and local craft markets','https://www.trip.com/guide/'),
('singapore','Singapore','新加坡','🇸🇬','Singapore','Kaya, tea & local design','咖椰酱、茶与本地设计','Design Orchard brings together proudly Singapore-made brands in one stop.','Design Orchard 汇集许多新加坡本土品牌，可一站式选购。','FairPrice and Design Orchard','https://www.trip.com/guide/'),
('thailand','Thailand','泰国','🇹🇭','Bangkok','Silk, wellness goods & snacks','丝绸、养生用品与零食','OTOP products are a strong place to start for regional specialities.','寻找地区特色商品时，OTOP 是很好的起点。','Big C, 7-Eleven, and craft markets','https://sg.trip.com/guide/info/what-to-buy-in-bangkok.html'),
('vietnam','Vietnam','越南','🇻🇳','Hanoi','Coffee, textiles & pantry gifts','咖啡、纺织品与食品礼物','Hanoi’s Old Quarter is a great place to compare craft shops; gentle haggling is expected.','河内老城区适合比较不同工艺店；温和议价很常见。','Supermarkets, Old Quarter, and craft stores','https://www.kkday.com/en/blog/61447/asia-vietnam-da-nang-best-souvenirs-to-buy');

